    uid: appUid,
  });

  await svix.endpoint.create(application.uid, {
    url: WEBHOOK_URL,
    description: "Non-existent endpoint for retry verification",
  });

  const message = await svix.message.create(application.uid, {
    eventType: "user.signup",
